import { Box, Flex } from '@chakra-ui/react';
import {
  ActionPageContentBlock,
  ActionPageContentBlockTextContent,
  ActionPageContentBlockVideo,
} from '@domain/actionPages';
import { SourceFrequency } from '@domain/entry';
import { PublicSubmission } from '@domain/submission';
import { useGetImage } from '@state/account_images';
import { useShowActionPage } from '@state/action_pages';
import { getPublicSubmission } from '@state/submissions';
