import { Flex, Stack } from '@chakra-ui/react';
import { EventTicket } from '@domain/events';
import { Divider } from '@ui/components/Divider';
import { Heading, Label, Meta } from '@ui/components/typography';
import { formatCurrency, formatDate } from '@ui/utils';
import { useMemo } from 'react';
import { Trans, useTranslation } from 'react-i18next';
import { AmountAllocations } from './AmountAllocations';
import { EventTicketSummary } from './EventTicketSummary';
import { FeesSection } from './FeesSection';
import { GOAReceiptSection } from './GOAReceiptSection';
import { StorefrontSummary } from './StorefrontSummary';
import { SubmissionSummaryProps } from './types';

type EventDisplayData = {
  fairMarketValue?: Nullable<number>;
  id: string;
  name: string;
  price: number;
  quantity: number;
  showFairMarketValue: boolean;
  ticketGroupName: Nullable<string>;
};

export const SubmissionSummary = ({
  aceProductSelections,
  amountAllocations,
  eventTickets,
  fees,
  frequency,
  giftOfAnyAmountProduct,
  isToday,
  nextChargeDate,
  promoCode,
  promoCodeBreakdown,
  storefrontProductSelections,
}: SubmissionSummaryProps) => {
  const { t } = useTranslation(['actionPageWorkflows', 'admin', 'common']);

  const ticketTotal = useMemo(() => {
    if (!eventTickets) {
      return 0;
    }

    return eventTickets.reduce((acc, curr) => acc + curr.price, 0);
  }, [eventTickets]);

  const total = useMemo(
    () =>
      amountAllocations.reduce((acc, { amount }) => acc + amount, 0) +
      (promoCodeBreakdown?.promoCodeSavings ?? 0),
    [amountAllocations, promoCodeBreakdown?.promoCodeSavings]
  );

  const hasDonation = total - ticketTotal > 0;
  const hasDonationOnly = !eventTickets || eventTickets.length === 0;

  const finalTotal = useMemo(
    () => total + (fees ?? 0) - (promoCodeBreakdown?.promoCodeSavings ?? 0),
    [total, fees, promoCodeBreakdown?.promoCodeSavings]
  );

  const ticketDisplayData = useMemo(() => {
    const data: EventDisplayData[] = [];
    const groupedData: Record<string, EventTicket[]> = {};

    if (eventTickets) {
      // create object with index of group position and value as the array of tickets in group
      eventTickets.forEach((ticket) => {
        if (!groupedData[ticket.ticketGroup.position]) {
          groupedData[ticket.ticketGroup.position] = [ticket];
        } else {
          groupedData[ticket.ticketGroup.position].push(ticket);
        }
      });

      // sort each group by ticket type position
      const sortedTicketGroups = Object.values(groupedData)
        .map((groups) =>
          groups.sort((a, b) => {
            const ticketPosition = a.ticketGroup.ticketGroupTicketTypes.find(
              (ticket) => ticket.ticketTypeId === a.ticketType.id
            )!.position;
            const nextTicketPosition = b.ticketGroup.ticketGroupTicketTypes.find(
              (ticket) => ticket.ticketTypeId === b.ticketType.id
            )!.position;

            return ticketPosition - nextTicketPosition;
          })
        )
        .flat();

      // create sorted ticket aray
      sortedTicketGroups.forEach((ticket: EventTicket) => {
        const currentTicketIndex = data.findIndex((item) => item.id === ticket?.ticketType.id);

        if (currentTicketIndex === -1) {
          data.push({
            fairMarketValue: ticket.ticketType.fairMarketValue,
            id: ticket.ticketType.id,
            name: ticket.ticketType.name,
            price: ticket.price,
            quantity: 1,
            showFairMarketValue: ticket.ticketType.showFairMarketValue,
            ticketGroupName: ticket.ticketGroup.name,
          });
        } else {
          data.map((item, index) => {
            if (item.id === ticket.ticketType.id) {
              data[index].quantity++;
            }
            return item;
          });
        }
      });
    }

    return data.length === 0 ? undefined : data;
  }, [eventTickets]);

  return (
    <Flex flexDirection="column" gap={4}>
      {!!aceProductSelections?.length && !!storefrontProductSelections?.length && (
        <StorefrontSummary
          aceProductSelections={aceProductSelections}
          storefrontProductSelections={storefrontProductSelections}
          total={total}
        />
      )}
      {!!ticketDisplayData && (
        <>
          <EventTicketSummary
            promoCode={promoCode}
            promoCodeBreakdown={promoCodeBreakdown}
            ticketDisplayData={ticketDisplayData}
          />
          {!!amountAllocations.length && <Divider borderColor="neutral.200" />}
        </>
      )}
      {hasDonation && !hasDonationOnly && (
        <Stack spacing={4}>
          <Flex justifyContent="space-between">
            <Label lineHeight={0.75}>Donation</Label>

            <Flex gap={2}>
              <Label textAlign="right" variant="bold" width="100px">
                {formatCurrency(total - ticketTotal)}
              </Label>
            </Flex>
          </Flex>
        </Stack>
      )}

      <Stack spacing={4}>
        {!hasDonationOnly && (
          <Heading as="h4" marginBottom={-2} marginTop={2}>
            {t('admin:fundAllocations.heading')}
          </Heading>
        )}

        {amountAllocations.map((fund) => {
          return (
            <AmountAllocations frequency={frequency} fund={fund} key={fund.actionPagesFundId} />
          );
        })}
      </Stack>
      {giftOfAnyAmountProduct && (
        <GOAReceiptSection giftOfAnyAmountProduct={giftOfAnyAmountProduct} />
      )}
      {!!fees && <FeesSection fees={fees} />}
      <Divider borderColor="neutral.200" />
      <Flex alignItems="center" justifyContent="flex-end">
        <Meta variant="allCaps">
          {isToday
            ? t('actionPageWorkflows:emailReceipt.summary.todaysTotal')
            : t('actionPageWorkflows:emailReceipt.summary.total')}
        </Meta>
        <Label textAlign="right" variant="bold" width="100px">
          {formatCurrency(finalTotal)}
        </Label>
      </Flex>
      {nextChargeDate && (
        <>
          <Divider borderColor="neutral.200" />
          <Stack spacing={4}>
            {amountAllocations.map((fund) => {
              return (
                <AmountAllocations frequency={frequency} fund={fund} key={fund.actionPagesFundId} />
              );
            })}
          </Stack>
          {!!fees && <FeesSection fees={fees} />}
          <Divider borderColor="neutral.200" />
          <Flex alignItems="center" justifyContent="flex-end">
            <Meta variant="allCaps">
              <Trans
                i18nKey="actionPageWorkflows:emailReceipt.summary.nextCharge"
                t={t}
                values={{ nextChargeDate: formatDate(nextChargeDate, 'ShortDate') }}
              />
            </Meta>
            <Label textAlign="right" variant="bold" width="100px">
              {formatCurrency(finalTotal)}
            </Label>
          </Flex>
        </>
      )}
    </Flex>
  );
};

