// Takes object, removes all undefined properties and if the object is empty, returns undefined
// e.g. { test: undefined } => undefined

import { isTruthy } from '@utils/isTruthy';

// { test: 'test', test2: undefined } => { test: 'test' }
const removeEmpty = (obj?: Record<string, unknown>): Record<string, unknown> | undefined => {
  const result = Object.fromEntries(Object.entries(obj ?? {}).filter(([_, v]) => !!v));
  if (Object.keys(result).length === 0) {
    return undefined;
  }
  return result as Record<string, string>;
};

type QueryKeyParams = {
  accountId?: string | null;
  parameters?: Record<string, unknown>;
  resourceId?: string | null;
  resourceKey: string;
  resourceType?: 'entity' | 'list';
};

type KeyElement = string | Record<string, unknown>;

export type GeneratedQueryKey = readonly KeyElement[];

export const generateQueryKey = ({
  accountId,
  parameters,
  resourceId,
  resourceKey,
  resourceType = 'list',
}: QueryKeyParams): GeneratedQueryKey => {
  return [
    accountId ? `accountId=${accountId}` : undefined,
    ...resourceKey.split('/'),
    resourceId,
    resourceType,
    removeEmpty(parameters),
  ].filter(isTruthy);
};

